#include <bits/stdc++.h>
using namespace std;vector<int>a;string o;
void solve(int s,int e){if(s>=e)return;int root=a[s],mid=s+1;while(mid<e&&a[mid]<root)mid++;solve(s+1,mid);solve(mid,e);o+=to_string(root)+"\n";}
int main(){int x;while(scanf("%d",&x)==1)a.push_back(x);solve(0,a.size());printf("%s",o.c_str());}
